const sourceId = $('Loop Sources').first().json.id;
const items = $input.all();
return items.map(item => ({
  json: {
    source_id: sourceId,
    title: item.json.title || '',
    url: item.json.link || '',
    published_at: item.json.isoDate || item.json.pubDate || null,
    summary: (item.json.contentSnippet || item.json.content || '').substring(0, 500)
  }
}));

const sourceId = $('Loop Sources').first().json.id;
const baseUrl = $('Loop Sources').first().json.base_url || '';
const items = $input.all();
return items.map(item => {
  let url = item.json.link || '';
  if (url && !url.startsWith('http')) {
    try { url = new URL(url, baseUrl).href; } catch(e) { url = baseUrl + url; }
  }
  return { json: { source_id: sourceId, title: item.json.title || '', url: url, published_at: null, summary: (item.json.summary || '').substring(0, 500) } };
});

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return "'" + String(val).replace(/\\/g, '\\\\').replace(/'/g, "\\'") + "'";
}
const items = $input.all();
for (const item of items) {
  const j = item.json;
  item.json.sql_query = "INSERT IGNORE INTO fn_news (source_id, title, url, url_hash, published_at, summary, status, created_at) VALUES ("
    + j.source_id + ", "
    + esc(j.title) + ", "
    + esc(j.url) + ", "
    + "SHA2(" + esc(j.url) + ", 256), "
    + (j.published_at ? esc(j.published_at) : "NULL") + ", "
    + esc(j.summary) + ", "
    + "'discovered', NOW())";
}
return items;

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return "'" + String(val).replace(/\\/g, '\\\\').replace(/'/g, "\\'") + "'";
}
const item = $input.first();
const prev = $('Loop News').first().json;
let html = item.json.data || '';
html = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');
html = html.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
html = html.replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '');
html = html.replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '');
html = html.replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '');
let text = html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 5000);

const prompt = `You are a numismatic news analyst for Foronum. Analyze this article and extract entities + classify it.

NEWS TITLE: ${prev.title}
NEWS DATE: ${prev.published_at || 'Unknown'}
ARTICLE TEXT:
${text}

RULES:
- New coin/banknote issues: score 80-100
- Auction results, mint announcements: 50-79
- Generic financial news: 0-39

OUTPUT (strict JSON only, no markdown):
{
  "entities": {"country":null,"denomination":null,"mint":null,"piece_type":null,"series":null,"year_referenced":null,"metal":null,"event_type":null},
  "all_entities": [],
  "score": 0,
  "classification": "high|medium|low|reject",
  "reasoning": "",
  "seo_potential": 0,
  "suggested_angle": ""
}`;

const htmlUpdateQuery = "UPDATE fn_news SET raw_html = " + esc(item.json.data || '') + ", updated_at = NOW() WHERE id = " + prev.id;

return [{ json: { ...prev, clean_text: text, llm_prompt: prompt, html_update_query: htmlUpdateQuery } }];

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return "'" + String(val).replace(/\\/g, '\\\\').replace(/'/g, "\\'") + "'";
}
const item = $input.first();
const prev = $('Clean & Prepare LLM').first().json;
let parsed;
try {
  parsed = JSON.parse(item.json.choices[0].message.content);
} catch(e) {
  parsed = { score: 0, classification: 'reject', reasoning: 'Parse error', entities: {}, all_entities: [], seo_potential: 0, suggested_angle: '' };
}
const e = parsed.entities || {};
return [{ json: {
  ...prev,
  llm_score: parsed.score || 0,
  llm_classification: parsed.classification || 'reject',
  llm_reasoning: parsed.reasoning || '',
  seo_potential: parsed.seo_potential || 0,
  suggested_angle: parsed.suggested_angle || '',
  country: e.country || null,
  denomination: e.denomination || null,
  mint: e.mint || null,
  piece_type: e.piece_type || null,
  series: e.series || null,
  year_referenced: e.year_referenced || null,
  metal: e.metal || null,
  event_type: e.event_type || null,
  entities_json: JSON.stringify(parsed.all_entities || [])
}}];

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return "'" + String(val).replace(/\\/g, '\\\\').replace(/'/g, "\\'") + "'";
}
const j = $input.first().json;
return [{ json: { sql_query: "UPDATE fn_news SET status = 'rejected', llm_score = " + j.llm_score + ", llm_classification = " + esc(j.llm_classification) + ", llm_reasoning = " + esc(j.llm_reasoning) + ", entities_json = " + esc(j.entities_json) + ", updated_at = NOW() WHERE id = " + j.id }}];

function esc(val) {
  if (val === null || val === undefined) return "''";
  return "'" + String(val).replace(/\\/g, '\\\\').replace(/'/g, "\\'") + "'";
}
const j = $input.first().json;
const terms = [j.country, j.series, j.denomination, j.mint].filter(Boolean);
if (terms.length === 0) terms.push(j.title);
const conditions = terms.map(t => "LOWER(entity_name) LIKE CONCAT('%', LOWER(" + esc(t) + "), '%')").join(' OR ');
return [{ json: { ...j, link_query: "SELECT * FROM fn_foronum_links WHERE is_active = 1 AND (" + conditions + ") ORDER BY seo_priority DESC" }}];

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return "'" + String(val).replace(/\\/g, '\\\\').replace(/'/g, "\\'") + "'";
}
const prev = $('Parse Classification').first().json;
const links = $input.all().map(i => i.json);
const languages = ['es', 'en', 'fr', 'de', 'it', 'pt'];
const priorityOrder = ['exact_coin', 'exact_banknote', 'series', 'country', 'topic'];
const resolved = {};
for (const lang of languages) {
  resolved[lang] = links.filter(l => l.lang === lang)
    .sort((a, b) => {
      const ai = priorityOrder.indexOf(a.entity_type);
      const bi = priorityOrder.indexOf(b.entity_type);
      if (ai !== bi) return ai - bi;
      return (b.seo_priority || 0) - (a.seo_priority || 0);
    }).slice(0, 4).map(l => ({ entity_type: l.entity_type, entity_name: l.entity_name, url: l.url, slug: l.slug, seo_priority: l.seo_priority }));
}
const linkCount = Math.max(...Object.values(resolved).map(a => a.length), 0);
const resolvedJson = JSON.stringify(resolved);

const sql = "UPDATE fn_news SET "
  + "clean_text = " + esc(prev.clean_text) + ", "
  + "entities_json = " + esc(prev.entities_json) + ", "
  + "country = " + esc(prev.country) + ", "
  + "denomination = " + esc(prev.denomination) + ", "
  + "mint = " + esc(prev.mint) + ", "
  + "piece_type = " + esc(prev.piece_type) + ", "
  + "series = " + esc(prev.series) + ", "
  + "year_referenced = " + esc(prev.year_referenced) + ", "
  + "metal = " + esc(prev.metal) + ", "
  + "event_type = " + esc(prev.event_type) + ", "
  + "llm_score = " + prev.llm_score + ", "
  + "llm_classification = " + esc(prev.llm_classification) + ", "
  + "llm_reasoning = " + esc(prev.llm_reasoning) + ", "
  + "seo_potential = " + prev.seo_potential + ", "
  + "resolved_links_json = " + esc(resolvedJson) + ", "
  + "link_count = " + linkCount + ", "
  + "status = 'enriched', "
  + "updated_at = NOW() WHERE id = " + prev.id;

return [{ json: { ...prev, resolved_links: resolved, resolved_links_json: resolvedJson, link_count: linkCount, sql_query: sql }}];

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return "'" + String(val).replace(/\\/g, '\\\\').replace(/'/g, "\\'") + "'";
}
const item = $input.first().json;
const resolvedLinks = JSON.parse(item.resolved_links_json || '{}');
const esLinks = (resolvedLinks.es || []).map(l => '- ' + l.entity_type + ': "' + l.entity_name + '" -> ' + l.url).join('\n');

const prompt = `Eres el redactor editorial IA de Foronum (foronum.com). Escribe un articulo en ESPANOL sobre esta noticia numismatica.

DIRECTRICES:
- Tono informativo, riguroso, accesible
- 400-800 palabras
- Incluir 2-4 enlaces internos con anchor text natural
- NUNCA inventes URLs. Solo usa las proporcionadas.
- Articulo sustancialmente original
- Sugerir imagen destacada

ENLACES INTERNOS PARA ESPANOL:
${esLinks}

NOTICIA:
Titulo: ${item.title}
Fuente: ${item.url} (citar, NO enlazar)
Entidades: ${item.entities_json || '[]'}
Resumen: ${item.summary || ''}
Texto: ${(item.clean_text || '').substring(0, 2000)}

OUTPUT (JSON estricto, sin markdown):
{"title":"max 70 chars","slug":"url-safe","excerpt":"150-200 chars","meta_description":"max 160 chars","body_html":"HTML valido","anchors_used":[{"text":"","url":"","entity_type":""}],"featured_image_suggestion":""}`;

return [{ json: { ...item, es_prompt: prompt, resolved_links: resolvedLinks }}];

const item = $input.first().json;
const prev = $('Prepare ES Prompt').first().json;
let esArticle;
try { esArticle = JSON.parse(item.choices[0].message.content); }
catch(e) { esArticle = {title:'Error',slug:'error',excerpt:'',meta_description:'',body_html:'<p>Error</p>',anchors_used:[],featured_image_suggestion:''}; }
return [{ json: { ...prev, es_article: esArticle, all_translations: { es: esArticle } }}];

const item = $input.first().json;
const langNames = {en:'English',fr:'French',de:'German',it:'Italian',pt:'Portuguese'};
return ['en','fr','de','it','pt'].map(lang => ({
  json: {
    ...item,
    target_lang: lang,
    target_lang_name: langNames[lang],
    target_links: (item.resolved_links[lang] || []).map(l => '- ' + l.entity_type + ': "' + l.entity_name + '" -> ' + l.url).join('\n')
  }
}));

const item = $input.first().json;
const es = item.es_article;
const prompt = `You are the editorial AI writer for Foronum. Generate a ${item.target_lang_name} version of this numismatic article.

IMPORTANT: NOT a literal translation. Use ${item.target_lang_name} internal links provided. Include 2-4 internal links. Generate appropriate slug.

REFERENCE (Spanish):
Title: ${es.title}
Body: ${es.body_html}

INTERNAL LINKS FOR ${item.target_lang.toUpperCase()}:
${item.target_links}

ENTITIES: ${item.entities_json || '[]'}

OUTPUT (strict JSON, no markdown):
{"title":"max 70 chars","slug":"url-safe","excerpt":"150-200 chars","meta_description":"max 160 chars","body_html":"valid HTML","anchors_used":[{"text":"","url":"","entity_type":""}],"featured_image_alt":"alt in ${item.target_lang_name}"}`;
return [{ json: { ...item, translation_prompt: prompt }}];

const item = $input.first().json;
const prev = $('Build Translation Prompt').first().json;
let translation;
try { translation = JSON.parse(item.choices[0].message.content); }
catch(e) { translation = {title:'Error',slug:'error',excerpt:'',meta_description:'',body_html:'<p>Error</p>',anchors_used:[],featured_image_alt:''}; }
return [{ json: { ...prev, current_translation: translation, current_lang: prev.target_lang }}];

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return "'" + String(val).replace(/\\/g, '\\\\').replace(/'/g, "\\'") + "'";
}
const item = $input.first().json;
const allTranslations = { es: item.es_article };
const parseOutputs = $('Parse Translation').all();
for (const o of parseOutputs) {
  allTranslations[o.json.current_lang] = o.json.current_translation;
}

const sourceText = (item.clean_text || '').toLowerCase();
const errors = [];
let worstOriginality = 100;

for (const lang of ['es','en','fr','de','it','pt']) {
  const t = allTranslations[lang];
  if (!t) { errors.push(lang + ': missing'); continue; }
  if ((t.title || '').length > 70) errors.push(lang + ': title > 70 chars');
  if ((t.meta_description || '').length > 160) errors.push(lang + ': meta > 160 chars');
  const bodyText = (t.body_html || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  const wordCount = bodyText.split(' ').length;
  if (wordCount < 300) errors.push(lang + ': body ' + wordCount + ' words (min 300)');
  const linkCount = (t.anchors_used || []).length;
  if (linkCount < 2) errors.push(lang + ': ' + linkCount + ' links (min 2)');
  if (linkCount > 4) errors.push(lang + ': ' + linkCount + ' links (max 4)');
  if (lang === 'es') {
    const srcWords = new Set(sourceText.split(/\s+/).filter(w => w.length > 3));
    const artWords = new Set(bodyText.toLowerCase().split(/\s+/).filter(w => w.length > 3));
    const inter = [...srcWords].filter(w => artWords.has(w)).length;
    const union = new Set([...srcWords, ...artWords]).size;
    const sim = union > 0 ? inter / union : 0;
    worstOriginality = Math.round((1 - sim) * 100);
    if (sim > 0.6) errors.push('es: too similar (' + Math.round(sim*100) + '%)');
  }
}

const isValid = errors.length === 0;
const validationNotes = errors.join('; ') || 'All OK';

let sql;
if (isValid) {
  sql = "INSERT INTO fn_articles (news_id, source_news_url, status, validation_notes, originality_score, created_at) VALUES ("
    + item.id + ", " + esc(item.url) + ", 'validated', " + esc(validationNotes) + ", " + worstOriginality + ", NOW())";
} else {
  sql = "INSERT INTO fn_articles (news_id, source_news_url, status, validation_notes, originality_score, created_at) VALUES ("
    + item.id + ", " + esc(item.url) + ", 'failed', " + esc(validationNotes) + ", " + worstOriginality + ", NOW())";
}

const translationQueries = [];
for (const lang of ['es','en','fr','de','it','pt']) {
  const t = allTranslations[lang] || {};
  translationQueries.push(
    "INSERT INTO fn_article_translations (article_id, lang, title, slug, excerpt, meta_description, body_html, anchors_used_json, internal_link_count, featured_image_url, featured_image_alt, created_at) VALUES ("
    + "LAST_INSERT_ID(), "
    + esc(lang) + ", "
    + esc(t.title || '') + ", "
    + esc(t.slug || '') + ", "
    + esc(t.excerpt || '') + ", "
    + esc(t.meta_description || '') + ", "
    + esc(t.body_html || '') + ", "
    + esc(JSON.stringify(t.anchors_used || [])) + ", "
    + (t.anchors_used || []).length + ", "
    + "NULL, "
    + esc(t.featured_image_alt || t.featured_image_suggestion || '') + ", "
    + "NOW())"
  );
}

const newsStatus = isValid ? 'article_ready' : 'error';
const newsUpdate = "UPDATE fn_news SET status = '" + newsStatus + "', updated_at = NOW() WHERE id = " + item.id;

return [{ json: {
  ...item,
  validation_passed: isValid,
  article_insert_query: sql,
  translation_queries: translationQueries,
  news_update_query: newsUpdate
}}];

const item = $input.first().json;
const prev = $('Collect & Validate').first().json;
return prev.translation_queries.map(q => ({ json: { sql_query: q }}));

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return "'" + String(val).replace(/\\/g, '\\\\').replace(/'/g, "\\'") + "'";
}
const j = $input.first().json;
const postInsert = "INSERT INTO foronum_posts (type, status, author_id, source_url, created_at) VALUES ('news_article', 'published', 1, " + esc(j.news_url || j.source_news_url) + ", NOW())";
const statusUpdate = "UPDATE fn_articles SET status = 'published', published_at = NOW(), updated_at = NOW() WHERE id = " + j.id;
const newsUpdate = "UPDATE fn_news SET status = 'published', updated_at = NOW() WHERE id = " + j.news_id;
return [{ json: { ...j, post_insert_query: postInsert, status_update_query: statusUpdate, news_update_query: newsUpdate }}];

const articles = $('Get Ready Articles').all();
const count = articles.length;
let body = '<h2>Pipeline Foronum ejecutado</h2>';
body += '<p>Articulos publicados: ' + count + '</p>';
for (const a of articles) {
  body += '<p>- ' + (a.json.source_news_url || a.json.news_url || '') + '</p>';
}
body += '<p><em>Generado automaticamente por n8n-foronum</em></p>';
return [{ json: { email_subject: '[Foronum] Pipeline: ' + count + ' articulos', email_body: body }}];
